return [
  {
    json: {
      prompt: `
You are an intent extractor.

Return ONLY valid JSON.
No explanation.
No extra text.

Expected format:
{
  "type": "action | question",
  "voucherType": "Sales | Purchase | Receipt | Payment | null",
  "amount": number | null,
  "ledger": string | null,
  "gst": { "enabled": boolean, "rate": number | null } | null
}

User input:
${$json.text}
`
    }
  }
];

let raw = $json.content || "";

// extract JSON from text
let jsonMatch = raw.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error("No JSON found in AI response");
}

let aiResponse;

try {
  aiResponse = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error("AI returned invalid JSON");
}

const state = {
  intent: aiResponse.intent || null,
  amount: aiResponse.amount || null,
  newAmount: aiResponse.newAmount || null,
  voucherType: aiResponse.voucherType || null,
  hasGST: aiResponse.hasGST ?? null,
  gstRate: aiResponse.gstRate ?? null,
  missing: aiResponse.missing || []
};

if (!state.intent) state.missing.push("intent");
if (!state.voucherType) state.missing.push("voucherType");
if (!state.amount) state.missing.push("amount");

return [
  {
    json: {
      state
    }
  }
];

// DELETE EVERYTHING AND PASTE THIS

const state = $json.state;

const errors = [];
const askUser = [];

// example rules
if (state.hasGST === true && !state.gstRate) {
  askUser.push("gstRate");
}

if (state.amount <= 0) {
  errors.push("Amount must be greater than zero");
}

if (askUser.length > 0) {
  return [
    {
      json: {
        status: "ASK_USER",
        askUser
      }
    }
  ];
}

if (errors.length > 0) {
  return [
    {
      json: {
        status: "ERROR",
        errors
      }
    }
  ];
}

return [
  {
    json: {
      status: "OK",
      state
    }
  }
];

// SAFE DEFAULT ROW (temporary, for pipeline test)
const row = {
  date: "2024-01-15",
  ledger: "Sales",
  amount: 2500,
  type: "debit"
};

// date format: YYYYMMDD
const tallyDate = row.date.replaceAll("-", "");

const isDebit = row.type.toLowerCase() === "debit";

const voucher = {
  TALLYREQUEST: "Import Data",
  REQUESTDATA: {
    TALLYMESSAGE: {
      VOUCHER: {
        DATE: tallyDate,
        VOUCHERTYPENAME: "Sales",
        PARTYLEDGERNAME: "Ram & Sons",
        ALLLEDGERENTRIES: [
          {
            LEDGERNAME: "Ram & Sons",
            ISDEEMEDPOSITIVE: "Yes",
            AMOUNT: -row.amount
          },
          {
            LEDGERNAME: "Sales",
            ISDEEMEDPOSITIVE: "No",
            AMOUNT: row.amount
          }
        ]
      }
    }
  }
};

return [{ json: voucher }];

// DELETE EVERYTHING AND PASTE THIS

const ctx = $json.context;

// -------- HARD VALIDATION (NO MERCY) ----------
if (!ctx) {
  throw new Error("Context missing");
}
if (!ctx.voucherType) {
  throw new Error("Voucher type missing");
}
if (!ctx.amount || Number(ctx.amount) <= 0) {
  throw new Error("Invalid amount");
}
if (!ctx.resolvedLedger) {
  throw new Error("Ledger missing");
}

// -------- BASIC VALUES ----------
const date = ctx.date || new Date().toISOString().slice(0,10).replace(/-/g,"");
const amount = Number(ctx.amount);

// -------- LEDGER ENTRIES ----------
const entries = `
<ALLLEDGERENTRIES.LIST>
  <LEDGERNAME>${ctx.resolvedLedger}</LEDGERNAME>
  <ISDEEMEDPOSITIVE>Yes</ISDEEMEDPOSITIVE>
  <AMOUNT>-${amount}</AMOUNT>
</ALLLEDGERENTRIES.LIST>

<ALLLEDGERENTRIES.LIST>
  <LEDGERNAME>Sales</LEDGERNAME>
  <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
  <AMOUNT>${amount}</AMOUNT>
</ALLLEDGERENTRIES.LIST>
`;

// -------- GST (OPTIONAL) ----------
let gstBlock = "";
if (ctx.gst && ctx.gst.enabled === true) {
  gstBlock = `
<ALLLEDGERENTRIES.LIST>
  <LEDGERNAME>Output GST</LEDGERNAME>
  <ISDEEMEDPOSITIVE>No</ISDEEMEDPOSITIVE>
  <AMOUNT>${ctx.gst.amount}</AMOUNT>
</ALLLEDGERENTRIES.LIST>
`;
}

// -------- FINAL XML ----------
const xml = `
<ENVELOPE>
 <HEADER>
  <TALLYREQUEST>Import Data</TALLYREQUEST>
 </HEADER>
 <BODY>
  <IMPORTDATA>
   <REQUESTDESC>
    <REPORTNAME>Vouchers</REPORTNAME>
   </REQUESTDESC>
   <REQUESTDATA>
    <TALLYMESSAGE>
     <VOUCHER VCHTYPE="${ctx.voucherType}" ACTION="Create">
      <DATE>${date}</DATE>
      <VOUCHERTYPENAME>${ctx.voucherType}</VOUCHERTYPENAME>
      <PARTYLEDGERNAME>${ctx.resolvedLedger}</PARTYLEDGERNAME>
      ${entries}
      ${gstBlock}
     </VOUCHER>
    </TALLYMESSAGE>
   </REQUESTDATA>
  </IMPORTDATA>
 </BODY>
</ENVELOPE>
`.trim();

return [
  {
    json: {
      xml
    }
  }
];

const ctx = $json.context || {};

if (!ctx.voucherType) {
  return [{
    json: {
      type: "question",
      question: "Voucher type batayiye (Sales / Purchase / Receipt / Payment)"
    }
  }];
}

ctx.voucherRules = {
  debit: ctx.voucherType !== "Sales",
  credit: ctx.voucherType === "Sales"
};

return [{ json: { context: ctx } }];

// Normalize Webhook Input

const body = $json.body || {};

if (!body.instruction || body.instruction.trim() === "") {
  return [{
    json: {
      type: "question",
      question: "Aap kya change karna chahte ho? Kripya instruction likhiye."
    }
  }];
}

return [{
  json: {
    instruction: body.instruction,
    context: body.context || {}
  }
}];

const prev = $json.context || {};

const next = {
  ...prev,
  ...$json
};

return [{
  json: {
    context: next
  }
}];

const ctx = $json.context || {};

if (!ctx.ledger) {
  return [{
    json: {
      type: "question",
      question: "Kaunsa ledger use karna hai? (Cash / Bank / Party name)"
    }
  }];
}

const map = {
  cash: "Cash",
  bank: "HDFC Bank"
};

ctx.resolvedLedger =
  map[ctx.ledger.toLowerCase()] || ctx.ledger;

return [{ json: { context: ctx } }];

const ctx = $json.context || {};

if (!ctx.gst || !ctx.gst.enabled) {
  ctx.gst = { enabled: false, amount: 0 };
  return [{ json: { context: ctx } }];
}

const rate = Number(ctx.gst.rate || 0);
const amt = Number(ctx.amount || 0);

ctx.gst.amount = (amt * rate) / 100;
ctx.gst.enabled = true;

return [{ json: { context: ctx } }];

const ctx = $json.context || {};
const errors = [];

if (!ctx.amount) errors.push("Amount missing");
if (!ctx.resolvedLedger) errors.push("Ledger missing");
if (!ctx.voucherType) errors.push("Voucher type missing");

if (errors.length) {
  return [{
    json: {
      type: "question",
      question: "Ye details missing hain: " + errors.join(", ")
    }
  }];
}

return [{ json: { context: ctx } }];

let data;

try {
  data = JSON.parse($json.content);
} catch (e) {
  return [{
    json: {
      type: "chat",
      reply: "Hello 👋, batao aap kya change karna chahte ho?"
    }
  }];
}

return [{ json: data }];

const rawMessage = items[0].json.context?.body?.instruction || "";
const message = rawMessage.toLowerCase().trim();

// Greeting detection
const greetings = ["hi", "hello", "hey", "good morning", "good evening"];
const isGreeting = greetings.includes(message);

// Question detection
const questionWords = ["what", "why", "how", "when", "where", "which", "meaning"];
const isQuestion = questionWords.some(word => message.includes(word));

// Command detection
const commandWords = [
  "create",
  "make",
  "generate",
  "pass",
  "add"
];

const voucherWords = [
  "voucher",
  "sale",
  "sales",
  "purchase",
  "receipt",
  "payment",
  "gst"
];

const hasCommandWord = commandWords.some(word => message.includes(word));
const hasVoucherWord = voucherWords.some(word => message.includes(word));

const isVoucherCommand = hasCommandWord && hasVoucherWord;

// Mixed detection
const isMixed = isVoucherCommand && isQuestion;

return [
  {
    json: {
      message,
      isGreeting,
      isQuestion,
      isVoucherCommand,
      isMixed
    }
  }
];

const msg = $json.message;

let reply = "";

if (msg.includes("how are you")) {
  reply = "I'm good. Tell me what you want to do in Tally.";
}
else if (msg.includes("who are you")) {
  reply = "I am your Tally AI assistant.";
}
else if (msg.includes("help")) {
  reply = "You can ask me to create vouchers or ask Tally related questions.";
}
else if (msg.includes("tally kya hai")) {
  reply = "Tally is accounting software used for bookkeeping, GST, and financial management.";
}
else if (msg.includes("gst rate")) {
  reply = "Common GST rates are 5%, 12%, 18%, and 28%.";
}
else {
  reply = "Hi! Tell me what you want to do.";
}

return [{
  reply
}];

